type Attributes
  (IDs   : IDs_Kind;
   Group : Process_Group_Kind) is
record
   case Group is
      when Custom => Group_ID : Spoon.Group_ID;
      when others => null;
   end case;
end record;

type Result (State : Exit_State) is record
   case State is
      when Error =>
         Error_Code : Integer;
      when Exited =>
         Exit_Status : Spoon.Exit_Status;
      when Crashed | Terminated =>
         Signal : Positive;
   end case;
end record;

